#include <stdio.h>
#include <stdlib.h>

struct TreeNode {
   int val;
   struct TreeNode *left;
   struct TreeNode *right;
};

bool isValidBST(struct TreeNode* root) {
   long long prev = -1e18;
   return inOrder(root, &prev);
}

bool inOrder(struct TreeNode* root, long long* prev) {
   if (!root) return true;
   if (!inOrder(root->left, prev)) return false;
   if (*prev >= root->val) return false;
   *prev = root->val;
   return inOrder(root->right, prev);
}

code.C++:
#include <iostream>
#include <climits>

struct TreeNode {
   int val;
   TreeNode *left;
   TreeNode *right;
   TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
   bool isValidBST(TreeNode* root) {
      long long prev = LLONG_MIN;
      return inOrder(root, prev);
   }

   bool inOrder(TreeNode* root, long long& prev) {
      if (!root) return true;
      if (!inOrder(root->left, prev)) return false;
      if (prev >= root->val) return false;
      prev = root->val;
      return inOrder(root->right, prev);
   }
};

code.Java:
class Solution {
   public boolean isValidBST(TreeNode root) {
      long[] prev = new long[] {Long.MIN_VALUE};
      return inOrder(root, prev);
   }

   private boolean inOrder(TreeNode root, long[] prev) {
      if (root == null) return true;
      if (!inOrder(root.left, prev)) return false;
      if (prev[0] >= root.val) return false;
      prev[0] = root.val;
      return inOrder(root.right, prev);
   }
}

